INSERT /*+ APPEND */ INTO NIC02B SELECT B.ENTY_ID AS RNMCNO /* 1 고객엔티티ID */ , CASE WHEN S1.NDVL_INSN_TYPE_CODE = 'IN' THEN CASE WHEN SUBSTR(A.RSDN_RGSN_BRDT,1,4) <= TO_CHAR(SYSDATE,'YYYY') AND SUBSTR(A.RSDN_RGSN_BRDT,5,2) BETWEEN '01' AND '12' AND SUBSTR(A.RSDN_RGSN_BRDT,7,2) BETWEEN '01' AND '31' THEN A.RSDN_RGSN_BRDT ELSE CASE WHEN SUBSTR(C.BRDT,1,4) <= TO_CHAR(SYSDATE,'YYYY') AND SUBSTR(C.BRDT,5,2) BETWEEN '01' AND '12' AND SUBSTR(C.BRDT,7,2) BETWEEN '01' AND '31' THEN C.BRDT ELSE CASE WHEN SUBSTR(Y.BRDT,1,4) <= TO_CHAR(SYSDATE,'YYYY') AND SUBSTR(Y.BRDT,5,2) BETWEEN '01' AND '12' AND SUBSTR(Y.BRDT,7,2) BETWEEN '01' AND '31' THEN Y.BRDT ELSE '' END END END ELSE ' ' END AS BRTDY /* 2 생년월일 */ , '1' AS BRTHDY_SL_LN_CLNDR_CD /* 3 생일양음력코드 */ -- 20240620 컴플라이언스 장영실선임 성별코드는 CDD내역의 성별 데이터로 변경 -- , CASE Y.GNDR_TYPE_CODE -- WHEN 'M' THEN '1' -- WHEN 'F' THEN '2' -- ELSE '9' -- END AS SEX_CD /* 4 성별코드 */ , CASE NVL(C.GNDR_SECT_CODE, '9') WHEN '1' THEN '1' WHEN '2' THEN '2' ELSE '9' END AS SEX_CD /* 4 성별코드 */ , CASE A.ENTY_ALIS_TYPE_CODE WHEN 'PSPT' THEN B.ENTY_ALIS_CRYP ELSE NULL END AS PSPT_NO /* 5 여권번호 */ , CASE WHEN TO_CHAR(D.PRCE_DATE_TIME,'YYYYMMDD') IS NOT NULL THEN CASE WHEN TRIM(I.CLNT_IFMN_CHAN_DATE) IS NOT NULL THEN CASE WHEN D.PRCE_DATE_TIME >= TO_DATE(I.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') AND TRIM(D.SITE_NAME) IS NOT NULL THEN TRIM(D.SITE_NAME) ELSE NVL(TRIM(A4.SITE_NAME),TRIM(D.SITE_NAME)) END ELSE CASE WHEN D.PRCE_DATE_TIME >= NVL(TO_DATE(TRIM(X.RGSN_DATE),'YYYYMMDD'),X.PRCE_DATE_TIME) AND TRIM(D.SITE_NAME) IS NOT NULL THEN TRIM(D.SITE_NAME) ELSE NVL(TRIM(A4.SITE_NAME),TRIM(D.SITE_NAME)) END END ELSE TRIM(A4.SITE_NAME) END AS WP_NM /* 6 직장명 */ , CASE WHEN TO_CHAR(D.PRCE_DATE_TIME,'YYYYMMDD') IS NOT NULL THEN CASE WHEN TRIM(H.CLNT_IFMN_CHAN_DATE) IS NOT NULL THEN CASE WHEN D.PRCE_DATE_TIME >= TO_DATE(H.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') AND TRIM(D.POSN_NAME) IS NOT NULL THEN TRIM(D.POSN_NAME) ELSE NVL(TRIM(A.FNCL_ROLE_NAME),TRIM(D.POSN_NAME)) END ELSE CASE WHEN D.PRCE_DATE_TIME >= NVL(TO_DATE(TRIM(X.RGSN_DATE),'YYYYMMDD'),X.PRCE_DATE_TIME) AND TRIM(D.POSN_NAME) IS NOT NULL THEN TRIM(D.POSN_NAME) ELSE NVL(TRIM(A.FNCL_ROLE_NAME),TRIM(D.POSN_NAME)) END END ELSE TRIM(A.FNCL_ROLE_NAME) END AS PSTN_CD /* 7 직위명 */ , NULL AS DTY_DPRT_NM /* 8 부서명 */ , X.PRCE_DATE_TIME AS HNDL_DY_TM /* 9 처리일시 */ , X.PCPR_ID AS L_HNDL_P_ENO /* 10 계정계처리자사번 */ , SYSDATE AS AML_CRT_DT /* 11 AML생성일자 */ , 'BATCH' AS AML_HNDL_P_ENO /* 12 AML처리자사번 */ , A4.JOB_CODE AS JOB_CODE /* 13 직업코드 */ , D.NDVL_TRDG_PRPS_CODE AS NDVL_TRDG_PRPS_CODE /* 개인거래목적코드 */ , D.NDVL_TRDG_PRPS_NAME AS NDVL_TRDG_PRPS_NAME /* 개인거래목적명 */ , D.NDVL_FUNS_ORIG_CODE AS NDVL_FUNS_ORIG_CODE /* 개인자금원천코드 */ , D.NDVL_FUNS_ORIG_NAME AS NDVL_FUNS_ORIG_NAME /* 개인자금원천명 */ , D.NDVL_FRCT_TRDG_CNT_CODE AS NDVL_FRCT_TRDG_CNT_CODE /* 개인예상거래횟수코드 */ , D.NDVL_FRCT_TRDG_SCL_CODE AS NDVL_FRCT_TRDG_SCL_CODE /* 개인예상거래규모코드 */ , D.ASMT_FNC_ASST_STN_CODE AS ASMT_FNC_ASST_STN_CODE /* 추정금융자산현황코드 */ FROM SID.IDO_A_UUE_LEGAL_ENTY X /* IDO_A_Entity_LegalEntity */ LEFT OUTER JOIN SID.IDO_A_UUE_BYBS_CLNT_CLSN X1 /* 폐쇄이관 관련정보 */ ON X.ENTY_ID = X1.ENTY_ID AND X1.VLD_YN = 'Y' AND X1.BYBS_CLNT_CLSN_TYPE_CODE = 'MV' LEFT OUTER JOIN SID.IDO_A_UUE_INDIVIDUAL Y ON X.ENTY_ID = Y.ENTY_ID , SID.IDO_A_UUF_CLNT_BSC S1 /* NDVL_INSN_TYPE_CODE */ , SID.IDO_A_UUF_CLNT_ADDN_IFMN A4 /* IDO_A_고객_고객부가정보 - JOB_CODE용 */ , SID.IDO_A_MAC_CLNT_ADDN_IFMN A LEFT OUTER JOIN SID.IDO_A_MAH_CDD_FLFL_DTLD C /* CDD수행내역 */ ON A.CLNT_ENTY_ID = C.CDD_TAGT_ENTY_ID
/* 직장, 직위명 관련 참조 ENTITY 추가 - B는 원래 있던 ENTITY : 2020.11 */ LEFT OUTER JOIN SID.IDO_A_MAH_EDD_FLFL_DTLD D /* EDD수행내역 */ ON C.CDD_TAGT_ENTY_ID = D.CDD_TAGT_ENTY_ID LEFT OUTER JOIN (SELECT /*+ FULL(F) PARALLEL(F 4) */ F.CLNT_ENTY_ID , MAX(F.CLNT_IFMN_CHAN_DATE) KEEP (DENSE_RANK FIRST ORDER BY F.CLNT_ENTY_ID, F.CLNT_IFMN_CHAN_DATE DESC) AS CLNT_IFMN_CHAN_DATE , MAX(REGEXP_REPLACE(TRIM(TO_SINGLE_BYTE(F.CLNT_IFMN_AFCH_CTNT)),'[0-9]|[@/.;*^,#!]|[?]')) KEEP (DENSE_RANK FIRST ORDER BY F.CLNT_ENTY_ID, F.CLNT_IFMN_CHAN_DATE DESC) AS CLNT_IFMN_AFCH_CTNT FROM SID.IDO_A_MAC_CLNT_ACNT_INF_CHG F WHERE F.CLNT_IFMN_CHAN_ITEM_CODE IN ('17') -- 직장명 AND REGEXP_REPLACE(TRIM(TO_SINGLE_BYTE(F.CLNT_IFMN_AFCH_CTNT)),'[0-9]|[@/.;*^,#!]|[?]') IS NOT NULL AND REGEXP_REPLACE(TRIM(TO_SINGLE_BYTE(F.CLNT_IFMN_AFCH_CTNT)),'[0-9]|[@/.;*^,#!]|[?]') <> 'test' GROUP BY F.CLNT_ENTY_ID ) H ON A.CLNT_ENTY_ID = H.CLNT_ENTY_ID LEFT OUTER JOIN (SELECT /*+ FULL(G) PARALLEL(G 4) */ G.CLNT_ENTY_ID , MAX(G.CLNT_IFMN_CHAN_DATE) KEEP (DENSE_RANK FIRST ORDER BY G.CLNT_ENTY_ID, G.CLNT_IFMN_CHAN_DATE DESC) AS CLNT_IFMN_CHAN_DATE , MAX(REGEXP_REPLACE(TRIM(TO_SINGLE_BYTE(G.CLNT_IFMN_AFCH_CTNT)),'[0-9]|[@/.;*^,#!]|[?]')) KEEP (DENSE_RANK FIRST ORDER BY G.CLNT_ENTY_ID, G.CLNT_IFMN_CHAN_DATE DESC) AS CLNT_IFMN_AFCH_CTNT FROM SID.IDO_A_MAC_CLNT_ACNT_INF_CHG G WHERE G.CLNT_IFMN_CHAN_ITEM_CODE IN ('18') -- 직위명 AND REGEXP_REPLACE(TRIM(TO_SINGLE_BYTE(G.CLNT_IFMN_AFCH_CTNT)),'[0-9]|[@/.;*^,#!]|[?]') IS NOT NULL AND REGEXP_REPLACE(TRIM(TO_SINGLE_BYTE(G.CLNT_IFMN_AFCH_CTNT)),'[0-9]|[@/.;*^,#!]|[?]') <> 'test' GROUP BY G.CLNT_ENTY_ID ) I ON A.CLNT_ENTY_ID = I.CLNT_ENTY_ID , SID.IDO_A_UUE_CLIENT_ENTY_ALIAS B WHERE X.ENTY_ID = A.CLNT_ENTY_ID AND A.CLNT_ENTY_ID = B.ENTY_ID AND A.ENTY_ALIS_TYPE_CODE = B.ENTY_ALIS_TYPE_CODE AND X1.BYBS_CLNT_CLSN_TYPE_CODE IS NULL /* 폐쇄이관 2단계고객은 제외 */ AND X.ENTY_ID = S1.ENTY_ID AND X.ENTY_ID = A4.ENTY_ID
--AND S1.NDVL_INSN_TYPE_CODE = 'IN' /* 고객구분이 개인 */ --AND C.CDD_CLNT_SECT_CODE <> '3' /* 20210828 고객정보는 개인이지만, CDD가 영리법인이면 --> 법인으로 마이그 */
/* 20211022 수정 */ AND (CASE WHEN S1.NDVL_INSN_TYPE_CODE <> 'IN' -- 고객정보 : 개인이 아니거나 OR (S1.NDVL_INSN_TYPE_CODE = 'IN' AND C.CDD_CLNT_SECT_CODE = '3') -- 고객정보 : 개인 & CDD : 비영리법인 ===> 법인으로 마이그 THEN '2' ELSE '1' END) = '1'
UNION ALL SELECT A.CDD_TAGT_ENTY_ID AS RNMCNO , TRIM(A.BRDT) AS BRTDY , '1' AS BRTHDY_SL_LN_CLNDR_CD , CASE A.GNDR_SECT_CODE WHEN '1' THEN '1' WHEN '2' THEN '2' ELSE '9' END AS SEX_CD , CASE WHEN A.RLNM_CNFM_TKN_CODE = '03' THEN A.CDD_TAGT_CLNT_NO_CRYP ELSE NULL END AS PSPT_CD , CASE WHEN TRIM(B.SITE_NAME) IS NOT NULL THEN TRIM(B.SITE_NAME) ELSE NULL END AS WP_NM , CASE WHEN TRIM(B.POSN_NAME ) IS NOT NULL THEN TRIM(B.POSN_NAME ) ELSE NULL END AS PSTN_CD , CASE WHEN TRIM(B.DPRT_NAME) IS NOT NULL THEN TRIM(B.DPRT_NAME) ELSE NULL END AS DTY_DPRT_NM , A.PRCE_DATE_TIME AS HNDL_DY_TM , A.PCPR_ID AS L_HNDL_P_ENO , SYSDATE AS AML_CRT_DT , 'BATCH' AS AML_HNDL_P_ENO , TRIM(A.JOB_CODE) AS JOB_CODE , TRIM(B.NDVL_TRDG_PRPS_CODE) AS NDVL_TRDG_PRPS_CODE , TRIM(B.NDVL_TRDG_PRPS_NAME) AS NDVL_TRDG_PRPS_NAME , TRIM(B.NDVL_FUNS_ORIG_CODE) AS NDVL_FUNS_ORIG_CODE , TRIM(B.NDVL_FUNS_ORIG_NAME) AS NDVL_FUNS_ORIG_NAME , TRIM(NDVL_FRCT_TRDG_CNT_CODE) AS NDVL_FRCT_TRDG_CNT_CODE , TRIM(NDVL_FRCT_TRDG_SCL_CODE) AS NDVL_FRCT_TRDG_SCL_CODE , TRIM(B.ASMT_FNC_ASST_STN_CODE) AS ASMT_FNC_ASST_STN_CODE FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A , SID.IDO_A_MAH_EDD_FLFL_DTLD B WHERE 1=1 AND A.CDD_TAGT_ENTY_ID = B.CDD_TAGT_ENTY_ID (+) AND A.CDD_FLFL_SQNO = B.CDD_FLFL_SQNO (+) AND A.CDD_CLNT_SECT_CODE = '1' AND NOT EXISTS (SELECT 1 FROM SID.IDO_A_MAC_CLNT_ADDN_IFMN WHERE CLNT_ENTY_ID = A.CDD_TAGT_ENTY_ID)

INSERT /*+ APPEND */ INTO SSQ.NIC05B SELECT T1.ENTY_ID AS RNMCNO , CASE WHEN T1.NDVL_INSN_TYPE_CODE = 'IN' THEN CASE WHEN T2.CDD_FLFL_DATE IS NOT NULL THEN CASE WHEN T4.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') >= TO_DATE(T4.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') AND TRIM(T2.CDD_CNTT_ADDR_TAGT_CODE) IS NOT NULL THEN T2.CDD_CNTT_ADDR_TAGT_CODE ELSE T1.ADDR_TYP_CCD END ELSE CASE WHEN T3.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') >= TO_DATE(T3.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') AND TRIM(T2.CDD_CNTT_ADDR_TAGT_CODE) IS NOT NULL THEN T2.CDD_CNTT_ADDR_TAGT_CODE ELSE T1.ADDR_TYP_CCD END ELSE T1.ADDR_TYP_CCD END END ELSE T1.ADDR_TYP_CCD END WHEN T1.NDVL_INSN_TYPE_CODE <> 'IN' THEN CASE WHEN T2.CDD_FLFL_DATE IS NOT NULL THEN CASE WHEN T4.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T4.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') > TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') THEN T1.ADDR_TYP_CCD ELSE T2.CDD_CNTT_ADDR_TAGT_CODE END ELSE CASE WHEN T1.RGSN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T1.RGSN_DATE,'YYYYMMDD')> TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') THEN T1.ADDR_TYP_CCD ELSE T2.CDD_CNTT_ADDR_TAGT_CODE END ELSE T2.CDD_CNTT_ADDR_TAGT_CODE END END ELSE T1.ADDR_TYP_CCD END ELSE T1.ADDR_TYP_CCD END AS ADDR_TYP_CCD , CASE WHEN T1.NDVL_INSN_TYPE_CODE = 'IN' THEN CASE WHEN T2.CDD_FLFL_DATE IS NOT NULL THEN CASE WHEN T4.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') >= TO_DATE(T4.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') AND TRIM(T2.PSTL_CODE) IS NOT NULL THEN T2.PSTL_CODE ELSE T1.PSTL_CODE END ELSE CASE WHEN T3.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') >= TO_DATE(T3.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') AND TRIM(T2.PSTL_CODE) IS NOT NULL THEN T2.PSTL_CODE ELSE T1.PSTL_CODE END ELSE T1.PSTL_CODE END END ELSE T1.PSTL_CODE END WHEN T1.NDVL_INSN_TYPE_CODE <> 'IN' THEN CASE WHEN T2.CDD_FLFL_DATE IS NOT NULL THEN CASE WHEN T4.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T4.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') > TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') THEN T1.PSTL_CODE ELSE T2.PSTL_CODE END ELSE CASE WHEN T1.RGSN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T1.RGSN_DATE,'YYYYMMDD') > TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') THEN T1.PSTL_CODE ELSE T2.PSTL_CODE END ELSE T2.PSTL_CODE END END ELSE T1.PSTL_CODE END ELSE T1.PSTL_CODE END AS PSTL_CODE , CASE WHEN T1.NDVL_INSN_TYPE_CODE = 'IN' THEN CASE WHEN T2.CDD_FLFL_DATE IS NOT NULL THEN CASE WHEN T4.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') >= TO_DATE(T4.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') AND TRIM(T2.BSC_ADRS_CRYP) IS NOT NULL THEN T2.BSC_ADRS_CRYP ELSE T1.BSC_ADRS_CRYP END ELSE CASE WHEN T3.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') >= TO_DATE(T3.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') AND TRIM(T2.BSC_ADRS_CRYP) IS NOT NULL THEN T2.BSC_ADRS_CRYP ELSE T1.BSC_ADRS_CRYP END ELSE T1.BSC_ADRS_CRYP END END ELSE T1.BSC_ADRS_CRYP END WHEN T1.NDVL_INSN_TYPE_CODE <> 'IN' THEN CASE WHEN T2.CDD_FLFL_DATE IS NOT NULL THEN CASE WHEN T4.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T4.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') > TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') THEN T1.BSC_ADRS_CRYP ELSE T2.BSC_ADRS_CRYP END ELSE CASE WHEN T1.RGSN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T1.RGSN_DATE,'YYYYMMDD') > TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') THEN T1.BSC_ADRS_CRYP ELSE T2.BSC_ADRS_CRYP END ELSE T2.BSC_ADRS_CRYP END END ELSE T1.BSC_ADRS_CRYP END ELSE T1.BSC_ADRS_CRYP END AS BSC_ADRS_CRYP , CASE WHEN T1.NDVL_INSN_TYPE_CODE = 'IN' THEN CASE WHEN T2.CDD_FLFL_DATE IS NOT NULL THEN CASE WHEN T4.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') >= TO_DATE(T4.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') AND TRIM(T2.DTLS_ADRS_CRYP) IS NOT NULL THEN T2.DTLS_ADRS_CRYP ELSE T1.DTLS_ADRS_CRYP END ELSE CASE WHEN T3.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') >= TO_DATE(T3.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') AND TRIM(T2.DTLS_ADRS_CRYP) IS NOT NULL THEN T2.DTLS_ADRS_CRYP ELSE T1.DTLS_ADRS_CRYP END ELSE T1.DTLS_ADRS_CRYP END END ELSE T1.DTLS_ADRS_CRYP END WHEN T1.NDVL_INSN_TYPE_CODE <> 'IN' THEN CASE WHEN T2.CDD_FLFL_DATE IS NOT NULL THEN CASE WHEN T4.CLNT_IFMN_CHAN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T4.CLNT_IFMN_CHAN_DATE,'YYYYMMDD') > TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') THEN T1.DTLS_ADRS_CRYP ELSE T2.DTLS_ADRS_CRYP END ELSE CASE WHEN T1.RGSN_DATE IS NOT NULL THEN CASE WHEN TO_DATE(T1.RGSN_DATE,'YYYYMMDD') > TO_DATE(T2.CDD_FLFL_DATE,'YYYYMMDD') THEN T1.DTLS_ADRS_CRYP ELSE T2.DTLS_ADRS_CRYP END ELSE T2.DTLS_ADRS_CRYP END END ELSE T1.DTLS_ADRS_CRYP END ELSE T1.DTLS_ADRS_CRYP END AS DTLS_ADRS_CRYP , T1.AML_CRT_DT , T1.AML_HNDL_P_ENO FROM ( SELECT ENTY_ID , ADDR_TYP_CCD , MAX(PSTL_CODE) KEEP(DENSE_RANK FIRST ORDER BY ENTY_ID, ADDR_TYP_CCD, CNTT_ADDR_ID, CNTT_ADDR_SQNO DESC) AS PSTL_CODE , MAX(BSC_ADRS_CRYP) KEEP(DENSE_RANK FIRST ORDER BY ENTY_ID, ADDR_TYP_CCD, CNTT_ADDR_ID, CNTT_ADDR_SQNO DESC) AS BSC_ADRS_CRYP , MAX(DTLS_ADRS_CRYP) KEEP(DENSE_RANK FIRST ORDER BY ENTY_ID, ADDR_TYP_CCD, CNTT_ADDR_ID, CNTT_ADDR_SQNO DESC) AS DTLS_ADRS_CRYP , SYSDATE AS AML_CRT_DT , 'BATCH' AS AML_HNDL_P_ENO , RGSN_DATE , NDVL_INSN_TYPE_CODE FROM (SELECT B.ENTY_ID , CASE WHEN D1.ENCT_TYPE_CODE IN ('PS','HQ') THEN '1' ELSE '2' END AS ADDR_TYP_CCD , D2.PSTL_CODE , D2.BSC_ADRS_CRYP , D2.DTLS_ADRS_CRYP , D1.ENCT_TYPE_CODE , D1.CNTT_ADDR_SQNO , D2.CNTT_ADDR_ID , SYSDATE AS AML_CRT_DT , 'BATCH' AS AML_HNDL_P_ENO , NVL(TRIM(X.RGSN_DATE),TO_CHAR(X.PRCE_DATE_TIME,'YYYYMMDD')) AS RGSN_DATE , S1.NDVL_INSN_TYPE_CODE AS NDVL_INSN_TYPE_CODE FROM SID.IDO_A_UUE_LEGAL_ENTY X , SID.IDO_A_MAC_CLNT_ADDN_IFMN A , SID.IDO_A_UUF_CLNT_BSC S1 /* NDVL_INSN_TYPE_CODE */ , SID.IDO_A_UUE_CLIENT_ENTY_ALIAS B , SID.IDO_A_UUE_ENTY_CONTACT D1 /*ENTITYCONTACT*/ , SID.IDO_A_UUE_ADDRESS D2 /*ADDRESS*/ WHERE X.ENTY_ID = A.CLNT_ENTY_ID AND A.CLNT_ENTY_ID = B.ENTY_ID AND A.ENTY_ALIS_TYPE_CODE = B.ENTY_ALIS_TYPE_CODE AND B.ENTY_ID = D1.ENTY_ID AND D1.CNTT_ADDR_BSWR_TYPE_CODE = 'CLNT' /* 연락처업무유형코드('CLNT':고객) */ AND S1.NDVL_INSN_TYPE_CODE = 'IN' /* 개인 */ AND D1.CNTT_ADDR_TYPE_CODE = 'ADR' /* 연락처유형코드('ADR':주소) */ AND D1.CNTT_ADDR_ID = D2.CNTT_ADDR_ID AND A.CLNT_ENTY_ID = S1.ENTY_ID ) GROUP BY ENTY_ID, ADDR_TYP_CCD, RGSN_DATE, NDVL_INSN_TYPE_CODE UNION ALL SELECT RNMCNO , ADDR_TYP_CCD , MAX(PSTL_CODE||PSTL_CODE1) KEEP(DENSE_RANK FIRST ORDER BY RNMCNO ) AS PSTL_CODE , MAX(BSC_ADRS_CRYP||BSC_ADRS_CRYP1) KEEP(DENSE_RANK FIRST ORDER BY RNMCNO ) AS BSC_ADRS_CRYP , MAX(DTLS_ADRS_CRYP||DTLS_ADRS_CRYP1) KEEP(DENSE_RANK FIRST ORDER BY RNMCNO ) AS DTLS_ADRS_CRYP , SYSDATE AS AML_CRT_DT , 'BATCH' AS AML_HNDL_P_ENO , RGSN_DATE , NDVL_INSN_TYPE_CODE FROM (SELECT B.ENTY_ID AS RNMCNO , '1' AS ADDR_TYP_CCD , CASE WHEN TRIM(D2.PSTL_CODE)||TRIM(D2.BSC_ADRS_CRYP)||TRIM(D2.DTLS_ADRS_CRYP) IS NOT NULL THEN CASE WHEN D1.ENCT_TYPE_CODE = 'HQ' THEN D2.PSTL_CODE ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'OF' THEN D2.PSTL_CODE ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'PS' THEN D2.PSTL_CODE ELSE NULL END END END ELSE NULL END AS PSTL_CODE , CASE WHEN TRIM(D2.PSTL_CODE)||TRIM(D2.BSC_ADRS_CRYP)||TRIM(D2.DTLS_ADRS_CRYP) IS NOT NULL THEN CASE WHEN D1.ENCT_TYPE_CODE = 'HQ' THEN D2.BSC_ADRS_CRYP ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'OF' THEN D2.BSC_ADRS_CRYP ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'PS' THEN D2.BSC_ADRS_CRYP ELSE NULL END END END ELSE NULL END AS BSC_ADRS_CRYP , CASE WHEN TRIM(D2.PSTL_CODE)||TRIM(D2.BSC_ADRS_CRYP)||TRIM(D2.DTLS_ADRS_CRYP) IS NOT NULL THEN CASE WHEN D1.ENCT_TYPE_CODE = 'HQ' THEN D2.DTLS_ADRS_CRYP ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'OF' THEN D2.DTLS_ADRS_CRYP ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'PS' THEN D2.DTLS_ADRS_CRYP ELSE NULL END END END ELSE NULL END AS DTLS_ADRS_CRYP , NULL AS PSTL_CODE1 , NULL AS BSC_ADRS_CRYP1 , NULL AS DTLS_ADRS_CRYP1 , NVL(TRIM(X.RGSN_DATE),TO_CHAR(X.PRCE_DATE_TIME,'YYYYMMDD')) AS RGSN_DATE , S1.NDVL_INSN_TYPE_CODE AS NDVL_INSN_TYPE_CODE FROM SID.IDO_A_UUE_LEGAL_ENTY X ,