_BSWR_TYPE_CODE = 'CLNT' /* 연락처업무유형코드('CLNT':고객) */ AND S1.NDVL_INSN_TYPE_CODE <> 'IN' /* 법인 */ AND D1.CNTT_ADDR_TYPE_CODE = 'ADR' /* 연락처유형코드('ADR':주소) */ AND D1.CNTT_ADDR_ID = D2.CNTT_ADDR_ID AND A.CLNT_ENTY_ID = S1.ENTY_ID
) GROUP BY RNMCNO, ADDR_TYP_CCD, RGSN_DATE, NDVL_INSN_TYPE_CODE UNION ALL SELECT RNMCNO , ADDR_TYP_CCD , PSTL_CODE , BSC_ADRS_CRYP , DTLS_ADRS_CRYP , AML_CRT_DT , AML_HNDL_P_ENO , RGSN_DATE , NDVL_INSN_TYPE_CODE FROM (SELECT D.CDD_TAGT_ENTY_ID AS RNMCNO , D.CDD_CNTT_ADDR_TAGT_CODE AS ADDR_TYP_CCD , MAX(D.PSTL_CODE) KEEP (DENSE_RANK FIRST ORDER BY D.CDD_TAGT_ENTY_ID, D.CDD_CNTT_ADDR_TAGT_CODE, D.CNTT_ADDR_ID, D.CDD_FLFL_SQNO DESC) AS PSTL_CODE , MAX(D.BSC_ADRS_CRYP) KEEP (DENSE_RANK FIRST ORDER BY D.CDD_TAGT_ENTY_ID, D.CDD_CNTT_ADDR_TAGT_CODE, D.CNTT_ADDR_ID, D.CDD_FLFL_SQNO DESC) AS BSC_ADRS_CRYP , MAX(D.DTLS_ADRS_CRYP) KEEP (DENSE_RANK FIRST ORDER BY D.CDD_TAGT_ENTY_ID, D.CDD_CNTT_ADDR_TAGT_CODE, D.CNTT_ADDR_ID, D.CDD_FLFL_SQNO DESC) AS DTLS_ADRS_CRYP , SYSDATE AS AML_CRT_DT , 'BATCH' AS AML_HNDL_P_ENO , MAX(D.CNTT_ADDR_ID) KEEP (DENSE_RANK FIRST ORDER BY D.CDD_TAGT_ENTY_ID, D.CDD_CNTT_ADDR_TAGT_CODE, D.CNTT_ADDR_ID, D.CDD_FLFL_SQNO DESC) AS CNTT_ADDR_ID , MAX(D.CDD_FLFL_DATE) KEEP (DENSE_RANK FIRST ORDER BY D.CDD_TAGT_ENTY_ID, D.CDD_CNTT_ADDR_TAGT_CODE, D.CNTT_ADDR_ID, D.CDD_FLFL_SQNO DESC) AS RGSN_DATE , (SELECT DISTINCT NDVL_INSN_TYPE_CODE FROM SID.IDO_A_UUF_CLNT_BSC WHERE ENTY_ID = D.CDD_TAGT_ENTY_ID) AS NDVL_INSN_TYPE_CODE FROM (SELECT A.CDD_TAGT_ENTY_ID , CASE WHEN B.CDD_CNTT_ADDR_TAGT_CODE IN ('12','14','22') THEN '1' ELSE '2' END AS CDD_CNTT_ADDR_TAGT_CODE , B.CDD_CNTT_ADDR_TAGT_CODE AS CDD_CNTT_ADDR_TAGT_CODE1 , B.CDD_FLFL_SQNO , TRIM(A.CDD_FLFL_DATE) AS CDD_FLFL_DATE , B.CNTT_ADDR_ID , C.PSTL_CODE , C.BSC_ADRS_CRYP , C.DTLS_ADRS_CRYP FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A , SID.IDO_A_MAH_CDD_CNTT_ADDR_IF B , SID.IDO_A_UUE_ADDRESS C WHERE A.CDD_TAGT_ENTY_ID = B.CDD_TAGT_ENTY_ID AND B.CDD_CNTT_ADDR_SECT_CODE = 'ADR' AND B.CNTT_ADDR_ID = C.CNTT_ADDR_ID AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL -- 12.개인CDD-자택, 13.개인CDD-직장, 14.개인CDD-실제거소 --, 21.법인CDD-사업장, 22.법인CDD-본점 AND B.CDD_CNTT_ADDR_TAGT_CODE IN ('12','13','14','21','22') ) D GROUP BY D.CDD_TAGT_ENTY_ID, D.CDD_CNTT_ADDR_TAGT_CODE ) E WHERE 1=1 AND NOT EXISTS (SELECT 1 FROM (SELECT B.ENTY_ID , CASE WHEN D1.ENCT_TYPE_CODE IN ('PS','HQ') THEN '1' ELSE '2' END AS ADDR_TYP_CCD FROM SID.IDO_A_UUE_LEGAL_ENTY X , SID.IDO_A_MAC_CLNT_ADDN_IFMN A , SID.IDO_A_UUF_CLNT_BSC S1 /* NDVL_INSN_TYPE_CODE */ , SID.IDO_A_UUE_CLIENT_ENTY_ALIAS B , SID.IDO_A_UUE_ENTY_CONTACT D1 /*ENTITYCONTACT*/ , SID.IDO_A_UUE_ADDRESS D2 /*ADDRESS*/ WHERE X.ENTY_ID = A.CLNT_ENTY_ID AND A.CLNT_ENTY_ID = B.ENTY_ID AND A.ENTY_ALIS_TYPE_CODE = B.ENTY_ALIS_TYPE_CODE AND B.ENTY_ID = D1.ENTY_ID AND D1.CNTT_ADDR_BSWR_TYPE_CODE = 'CLNT' /* 연락처업무유형코드('CLNT':고객) */ AND S1.NDVL_INSN_TYPE_CODE = 'IN' /* 개인 */ AND D1.CNTT_ADDR_TYPE_CODE = 'ADR' /* 연락처유형코드('ADR':주소) */ AND D1.CNTT_ADDR_ID = D2.CNTT_ADDR_ID AND A.CLNT_ENTY_ID = S1.ENTY_ID GROUP BY B.ENTY_ID, (CASE WHEN D1.ENCT_TYPE_CODE IN ('PS','HQ') THEN '1' ELSE '2' END) UNION ALL SELECT RNMCNO , ADDR_TYP_CCD FROM (SELECT B.ENTY_ID AS RNMCNO , '1' AS ADDR_TYP_CCD , CASE WHEN TRIM(D2.PSTL_CODE)||TRIM(D2.BSC_ADRS_CRYP)||TRIM(D2.DTLS_ADRS_CRYP) IS NOT NULL THEN CASE WHEN D1.ENCT_TYPE_CODE = 'HQ' THEN D2.PSTL_CODE ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'OF' THEN D2.PSTL_CODE ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'PS' THEN D2.PSTL_CODE ELSE NULL END END END ELSE NULL END AS PSTL_CODE , CASE WHEN TRIM(D2.PSTL_CODE)||TRIM(D2.BSC_ADRS_CRYP)||TRIM(D2.DTLS_ADRS_CRYP) IS NOT NULL THEN CASE WHEN D1.ENCT_TYPE_CODE = 'HQ' THEN D2.BSC_ADRS_CRYP ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'OF' THEN D2.BSC_ADRS_CRYP ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'PS' THEN D2.BSC_ADRS_CRYP ELSE NULL END END END ELSE NULL END AS BSC_ADRS_CRYP , CASE WHEN TRIM(D2.PSTL_CODE)||TRIM(D2.BSC_ADRS_CRYP)||TRIM(D2.DTLS_ADRS_CRYP) IS NOT NULL THEN CASE WHEN D1.ENCT_TYPE_CODE = 'HQ' THEN D2.DTLS_ADRS_CRYP ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'OF' THEN D2.DTLS_ADRS_CRYP ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'PS' THEN D2.DTLS_ADRS_CRYP ELSE NULL END END END ELSE NULL END AS DTLS_ADRS_CRYP , NULL AS PSTL_CODE1 , NULL AS BSC_ADRS_CRYP1 , NULL AS DTLS_ADRS_CRYP1 , NVL(TRIM(X.RGSN_DATE),TO_CHAR(X.PRCE_DATE_TIME,'YYYYMMDD')) AS RGSN_DATE , S1.NDVL_INSN_TYPE_CODE AS NDVL_INSN_TYPE_CODE FROM SID.IDO_A_UUE_LEGAL_ENTY X , SID.IDO_A_MAC_CLNT_ADDN_IFMN A , SID.IDO_A_UUF_CLNT_BSC S1 /* NDVL_INSN_TYPE_CODE */ , SID.IDO_A_UUE_CLIENT_ENTY_ALIAS B , SID.IDO_A_UUE_ENTY_CONTACT D1 /*ENTITYCONTACT*/ , SID.IDO_A_UUE_ADDRESS D2 /*ADDRESS*/ WHERE X.ENTY_ID = A.CLNT_ENTY_ID AND A.CLNT_ENTY_ID = B.ENTY_ID AND A.ENTY_ALIS_TYPE_CODE = B.ENTY_ALIS_TYPE_CODE AND B.ENTY_ID = D1.ENTY_ID AND D1.CNTT_ADDR_BSWR_TYPE_CODE = 'CLNT' /* 연락처업무유형코드('CLNT':고객) */ AND S1.NDVL_INSN_TYPE_CODE <> 'IN' /* 법인 */ AND D1.CNTT_ADDR_TYPE_CODE = 'ADR' /* 연락처유형코드('ADR':주소) */ AND D1.CNTT_ADDR_ID = D2.CNTT_ADDR_ID AND A.CLNT_ENTY_ID = S1.ENTY_ID UNION ALL SELECT B.ENTY_ID AS RNMCNO , '2' AS ADDR_TYP_CCD , NULL AS PSTL_CODE , NULL AS BSC_ADRS_CRYP , NULL AS DTLS_ADRS_CRYP , CASE WHEN TRIM(D2.PSTL_CODE)||TRIM(D2.BSC_ADRS_CRYP)||TRIM(D2.DTLS_ADRS_CRYP) IS NOT NULL THEN CASE WHEN D1.ENCT_TYPE_CODE = 'OF' THEN D2.PSTL_CODE ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'PS' THEN D2.PSTL_CODE ELSE NULL END END END AS PSTL_CODE1 , CASE WHEN TRIM(D2.PSTL_CODE)||TRIM(D2.BSC_ADRS_CRYP)||TRIM(D2.DTLS_ADRS_CRYP) IS NOT NULL THEN CASE WHEN D1.ENCT_TYPE_CODE = 'OF' THEN D2.BSC_ADRS_CRYP ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'PS' THEN D2.BSC_ADRS_CRYP ELSE NULL END END END AS PSTL_CODE1 , CASE WHEN TRIM(D2.PSTL_CODE)||TRIM(D2.BSC_ADRS_CRYP)||TRIM(D2.DTLS_ADRS_CRYP) IS NOT NULL THEN CASE WHEN D1.ENCT_TYPE_CODE = 'OF' THEN D2.DTLS_ADRS_CRYP ELSE CASE WHEN D1.ENCT_TYPE_CODE = 'PS' THEN D2.DTLS_ADRS_CRYP ELSE NULL END END END AS DTLS_ADRS_CRYP1 , NVL(TRIM(X.RGSN_DATE),TO_CHAR(X.PRCE_DATE_TIME,'YYYYMMDD')) AS RGSN_DATE , S1.NDVL_INSN_TYPE_CODE AS NDVL_INSN_TYPE_CODE FROM SID.IDO_A_UUE_LEGAL_ENTY X , SID.IDO_A_MAC_CLNT_ADDN_IFMN A , SID.IDO_A_UUF_CLNT_BSC S1 /* NDVL_INSN_TYPE_CODE */ , SID.IDO_A_UUE_CLIENT_ENTY_ALIAS B , SID.IDO_A_UUE_ENTY_CONTACT D1 /*ENTITYCONTACT*/ , SID.IDO_A_UUE_ADDRESS D2 /*ADDRESS*/ WHERE X.ENTY_ID = A.CLNT_ENTY_ID AND A.CLNT_ENTY_ID = B.ENTY_ID AND A.ENTY_ALIS_TYPE_CODE = B.ENTY_ALIS_TYPE_CODE AND B.ENTY_ID = D1.ENTY_ID AND D1.CNTT_ADDR_BSWR_TYPE_CODE = 'CLNT' /* 연락처업무유형코드('CLNT':고객) */ AND S1.NDVL_INSN_TYPE_CODE <> 'IN' /* 법인 */ AND D1.CNTT_ADDR_TYPE_CODE = 'ADR' /* 연락처유형코드('ADR':주소) */ AND D1.CNTT_ADDR_ID = D2.CNTT_ADDR_ID AND A.CLNT_ENTY_ID = S1.ENTY_ID
) GROUP BY RNMCNO, ADDR_TYP_CCD ) WHERE ENTY_ID = E.RNMCNO AND ADDR_TYP_CCD = E.ADDR_TYP_CCD ) ) T1, (SELECT CDD_TAGT_ENTY_ID , CDD_CNTT_ADDR_TAGT_CODE , MAX(CDD_FLFL_DATE) KEEP (DENSE_RANK FIRST ORDER BY CDD_TAGT_ENTY_ID, CDD_CNTT_ADDR_TAGT_CODE, CNTT_ADDR_ID, CDD_FLFL_SQNO DESC) AS CDD_FLFL_DATE , MAX(CNTT_ADDR_ID) KEEP (DENSE_RANK FIRST ORDER BY CDD_TAGT_ENTY_ID, CDD_CNTT_ADDR_TAGT_CODE, CNTT_ADDR_ID, CDD_FLFL_SQNO DESC) AS CNTT_ADDR_ID , MAX(PSTL_CODE) KEEP (DENSE_RANK FIRST ORDER BY CDD_TAGT_ENTY_ID, CDD_CNTT_ADDR_TAGT_CODE, CNTT_ADDR_ID, CDD_FLFL_SQNO DESC) AS PSTL_CODE , MAX(BSC_ADRS_CRYP) KEEP (DENSE_RANK FIRST ORDER BY CDD_TAGT_ENTY_ID, CDD_CNTT_ADDR_TAGT_CODE, CNTT_ADDR_ID, CDD_FLFL_SQNO DESC) AS BSC_ADRS_CRYP , MAX(DTLS_ADRS_CRYP) KEEP (DENSE_RANK FIRST ORDER BY CDD_TAGT_ENTY_ID, CDD_CNTT_ADDR_TAGT_CODE, CNTT_ADDR_ID, CDD_FLFL_SQNO DESC) AS DTLS_ADRS_CRYP FROM (SELECT A.CDD_TAGT_ENTY_ID , CASE WHEN B.CDD_CNTT_ADDR_TAGT_CODE IN ('12','14','22') THEN '1' ELSE '2' END AS CDD_CNTT_ADDR_TAGT_CODE , B.CDD_CNTT_ADDR_TAGT_CODE AS CDD_CNTT_ADDR_TAGT_CODE1 , B.CDD_FLFL_SQNO , TRIM(A.CDD_FLFL_DATE) AS CDD_FLFL_DATE , B.CNTT_ADDR_ID , C.PSTL_CODE , C.BSC_ADRS_CRYP , C.DTLS_ADRS_CRYP FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A , SID.IDO_A_MAH_CDD_CNTT_ADDR_IF B , SID.IDO_A_UUE_ADDRESS C WHERE A.CDD_TAGT_ENTY_ID = B.CDD_TAGT_ENTY_ID AND B.CDD_CNTT_ADDR_SECT_CODE = 'ADR' AND B.CNTT_ADDR_ID = C.CNTT_ADDR_ID AND TRIM(A.CDD_FLFL_DATE) IS NOT NULL -- 12.개인CDD-자택, 13.개인CDD-직장, 14.개인CDD-실제거소 --, 21.법인CDD-사업장, 22.법인CDD-본점 AND B.CDD_CNTT_ADDR_TAGT_CODE IN ('12','13','14','21','22') ) GROUP BY CDD_TAGT_ENTY_ID, CDD_CNTT_ADDR_TAGT_CODE ) T2, (SELECT F.CLNT_ENTY_ID , '1' AS ADDR_TYP_CCD , MAX(F.CLNT_IFMN_CHAN_DATE) KEEP (DENSE_RANK FIRST ORDER BY F.CLNT_ENTY_ID, F.CLNT_IFMN_CHAN_DATE DESC) AS CLNT_IFMN_CHAN_DATE , MAX(TRIM(CLNT_IFMN_AFCH_CTNT)) KEEP (DENSE_RANK FIRST ORDER BY F.CLNT_ENTY_ID, F.CLNT_IFMN_CHAN_DATE DESC) AS CLNT_IFMN_AFCH_CTNT FROM SID.IDO_A_MAC_CLNT_ACNT_INF_CHG F WHERE F.CLNT_IFMN_CHAN_ITEM_CODE IN ('24') -- 주소(자택) AND TRIM(CLNT_IFMN_AFCH_CTNT) IS NOT NULL GROUP BY F.CLNT_ENTY_ID) T3, ( SELECT F.CLNT_ENTY_ID , '2' AS ADDR_TYP_CCD , MAX(F.CLNT_IFMN_CHAN_DATE) KEEP (DENSE_RANK FIRST ORDER BY F.CLNT_ENTY_ID, F.CLNT_IFMN_CHAN_DATE DESC) AS CLNT_IFMN_CHAN_DATE , MAX(TRIM(CLNT_IFMN_AFCH_CTNT)) KEEP (DENSE_RANK FIRST ORDER BY F.CLNT_ENTY_ID, F.CLNT_IFMN_CHAN_DATE DESC) AS CLNT_IFMN_AFCH_CTNT FROM SID.IDO_A_MAC_CLNT_ACNT_INF_CHG F WHERE F.CLNT_IFMN_CHAN_ITEM_CODE IN ('25') -- 주소(직장) AND TRIM(CLNT_IFMN_AFCH_CTNT) IS NOT NULL GROUP BY F.CLNT_ENTY_ID ) T4, ( SELECT F.CLNT_ENTY_ID , '1' AS ADDR_TYP_CCD , MAX(F.CLNT_IFMN_CHAN_DATE) KEEP (DENSE_RANK FIRST ORDER BY F.CLNT_ENTY_ID, F.CLNT_IFMN_CHAN_DATE DESC) AS CLNT_IFMN_CHAN_DATE , MAX(TRIM(CLNT_IFMN_AFCH_CTNT)) KEEP (DENSE_RANK FIRST ORDER BY F.CLNT_ENTY_ID, F.CLNT_IFMN_CHAN_DATE DESC) AS CLNT_IFMN_AFCH_CTNT FROM SID.IDO_A_MAC_CLNT_ACNT_INF_CHG F WHERE F.CLNT_IFMN_CHAN_ITEM_CODE IN ('L3') -- 주소(본점) AND TRIM(CLNT_IFMN_AFCH_CTNT) IS NOT NULL GROUP BY F.CLNT_ENTY_ID) T5 WHERE T1.ENTY_ID = T2.CDD_TAGT_ENTY_ID (+) AND T1.ADDR_TYP_CCD = T2.CDD_CNTT_ADDR_TAGT_CODE (+) AND T1.ENTY_ID = T3.CLNT_ENTY_ID (+) AND T1.ADDR_TYP_CCD = T3.ADDR_TYP_CCD (+) AND T1.ENTY_ID = T4.CLNT_ENTY_ID (+) AND T1.ADDR_TYP_CCD = T4.ADDR_TYP_CCD (+) AND T1.ENTY_ID = T5.CLNT_ENTY_ID (+) AND T1.ADDR_TYP_CCD = T5.ADDR_TYP_CCD (+) UNION /* MODIFY */ SELECT A.CDD_TAGT_ENTY_ID AS RNMCNO , B.ADDR_TYP_CCD , B.PSTL_CODE AS PST_NO , B.BSC_ADRS_CRYP AS BSC_ADDR , B.DTLS_ADRS_CRYP AS DNG_FLWG_ADDR , SYSDATE AS AML_CRT_DT , 'BATCH' AS AML_HNDL_P_ENO FROM SID.IDO_A_MAH_CDD_FLFL_DTLD A , (SELECT CDD_TAGT_ENTY_ID , ADDR_TYP_CCD , MAX(PSTL_CODE) KEEP(DENSE_RANK FIRST ORDER BY CDD_TAGT_ENTY_ID, ADDR_TYP_CCD, CNTT_ADDR_ID, CDD_FLFL_SQNO DESC) AS PSTL_CODE , MAX(BSC_ADRS_CRYP) KEEP(DENSE_RANK FIRST ORDER BY CDD_TAGT_ENTY_ID, ADDR_TYP_CCD, CNTT_ADDR_ID, CDD_FLFL_SQNO DESC) AS BSC_ADRS_CRYP , MAX(DTLS_ADRS_CRYP) KEEP(DENSE_RANK FIRST ORDER BY CDD_TAGT_ENTY_ID, ADDR_TYP_CCD, CNTT_ADDR_ID, CDD_FLFL_SQNO DESC) AS DTLS_ADRS_CRYP FROM (SELECT B.CDD_TAGT_ENTY_ID , CASE WHEN B.CDD_CNTT_ADDR_TAGT_CODE IN ('12','14','22') THEN '1' ELSE '2' END AS ADDR_TYP_CCD , B.CDD_FLFL_SQNO , B.CNTT_ADDR_ID , C.PSTL_CODE , C.BSC_ADRS_CRYP , C.DTLS_ADRS_CRYP FROM SID.IDO_A_MAH_CDD_CNTT_ADDR_IF B , SID.IDO_A_UUE_ADDRESS C WHERE B.CDD_CNTT_ADDR_SECT_CODE = 'ADR' AND B.CNTT_ADDR_ID = C.CNTT_ADDR_ID -- 12.개인CDD-자택, 13.개인CDD-직장, 14.개인CDD-실제거소 --, 21.법인CDD-사업장, 22.법인CDD-본점 AND B.CDD_CNTT_ADDR_TAGT_CODE IN ('12','13','14','21','22') ) GROUP BY CDD_TAGT_ENTY_ID, ADDR_TYP_CCD) B WHERE A.CDD_TAGT_ENTY_ID = B.CDD_TAGT_ENTY_ID AND NOT EXISTS (SELECT 1 FROM SID.IDO_A_MAC_CLNT_ADDN_IFMN C WHERE C.CLNT_ENTY_ID = A.CDD_TAGT_ENTY_ID)

MERGE INTO SSQ.NIC45B A USING ( SELECT STND_PRDT_CLSN_CODE AS GDS_NO /* 1 표준상품분류코드 */ , CASE WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'A' THEN '21' /* 주식 */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'B' THEN '51' /* 파생(선물) */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'C' THEN '52' /* 파생(옵션) */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'D' THEN '31' /* 채권(기명) */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'E' THEN '59' /* 파생(기타)기재 */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'F' THEN CASE WHEN STND_PRDT_CLSN_CODE IN ('F1012','F1112','F1212','F1312','F1412') THEN '51' /* 파생(선물) */ WHEN STND_PRDT_CLSN_CODE IN ('F1011','F1111','F1211','F1311','F1411') THEN '52' /* 파생(옵션) */ WHEN STND_PRDT_CLSN_CODE IN ('F1013','F1113','F1213','F1313','F1413') THEN '53' /* 파생(스왑) */ WHEN STND_PRDT_CLSN_CODE IN ('F1010','F1110','F1210','F1310','F1410') THEN '59' /* 파생(기타)기재 */ ELSE '99' /* 기타 */ END WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'G' THEN '12' /* 투자신탁 */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'H' THEN '24' /* Wrap */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'I' THEN '11' /* 신탁 */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'J' THEN '26' /* 퇴직연금 */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'K' THEN CASE WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,3) = 'K13' THEN '61' /* 보험(보장) */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,3) = 'K11' THEN '62' /* 보험(연금) */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,3) = 'K10' THEN '63' /* 보험(저축) */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,3) = 'K12' THEN '64' /* 보험(투자) */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,3) = 'K14' THEN '65' /* 보험(일반손해) */ ELSE '99' /* 기타 */ END WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'L' THEN '64' /* 보험(투자) */ WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'M' THEN CASE WHEN STND_PRDT_CLSN_CODE IN ('M1210','M1211','M1610','M1612') THEN '01' /* 수시입출금 예금 */ WHEN STND_PRDT_CLSN_CODE IN ('M1611','M1614','M1615','M1616') THEN '03' /* 거치식 예금 */ WHEN STND_PRDT_CLSN_CODE IN ('M1613') THEN '23' /* CMA */ ELSE '99' /* 기타 */ END WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'N' THEN CASE WHEN STND_PRDT_CLSN_CODE IN ('N1711','N1712') THEN '01' /* 수시입출금 예금 */ ELSE '99' /* 기타 */ END WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) IN ('O','P','X') THEN '99' /* 기타 */ ELSE '99' /* 기타 */ END AS GDS_DIT_CD /* 2 KOFIU상품분류코드 */ , STND_PRDT_CLSN_CODE_NAME AS GDS_NM /* 3 표준상품분류코드명 */ , CASE WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'A' THEN '주식' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'B' THEN '파생(선물)' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'C' THEN '파생(옵션)' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'D' THEN '채권(기명)' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'E' THEN '파생(기타)기재' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'F' THEN CASE WHEN STND_PRDT_CLSN_CODE IN ('F1012','F1112','F1212','F1312','F1412') THEN '파생(선물)' WHEN STND_PRDT_CLSN_CODE IN ('F1011','F1111','F1211','F1311','F1411') THEN '파생(옵션)' WHEN STND_PRDT_CLSN_CODE IN ('F1013','F1113','F1213','F1313','F1413') THEN '파생(스왑)' WHEN STND_PRDT_CLSN_CODE IN ('F1010','F1110','F1210','F1310','F1410') THEN '파생(기타)기재' ELSE '기타' END WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'G' THEN '투자신탁' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'H' THEN 'Wrap' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'I' THEN '신탁' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'J' THEN '퇴직연금' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'K' THEN CASE WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,3) = 'K13' THEN '보험(보장)' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,3) = 'K11' THEN '보험(연금)' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,3) = 'K10' THEN '보험(저축)' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,3) = 'K12' THEN '보험(투자)' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,3) = 'K14' THEN '보험(일반손해)' ELSE '기타' END WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'L' THEN '보험(투자)' WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'M' THEN CASE WHEN STND_PRDT_CLSN_CODE IN ('M1210','M1211','M1610','M1612') THEN '수시입출금예금' WHEN STND_PRDT_CLSN_CODE IN ('M1611','M1614','M1615','M1616') THEN '거치식예금' WHEN STND_PRDT_CLSN_CODE IN ('M1613') THEN 'CMA' ELSE '기타' END WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) = 'N' THEN CASE WHEN STND_PRDT_CLSN_CODE IN ('N1711','N1712') THEN '수시입출금예금' ELSE '기타' END WHEN SUBSTR(STND_PRDT_CLSN_CODE,1,1) IN ('O','P','X') THEN '기타' ELSE '기타' END AS GDS_DIT_NM /* 4 표준상품분류코드명 */ , 0 AS GDS_MRK /* 5 상품RA점수 */ , PRCE_DATE_TIME AS HNDL_DY_TM /* 6 처리일시 */ , 0 AS HNDL_P_ENO /* 7 처리자사번 */ , SYSDATE AS AML_CRT_DT /* 8 AML생성일자 */ , PCPR_ID AS AML_HNDL_P_ENO /* 9 AML처리자사번 */ , STND_PRDT_LARG_CLSN_CODE AS LEV1_CD /* 10 표준상품대분류코드 */ , STND_PRDT_MDUM_CLSN_CODE AS LEV2_CD /* 11 표준상품중분류코드 */ , STND_PRDT_LARG_CLSN_CODE_NAME AS LEV1_NM /* 12 표준상품대분류코드명 */ , STND_PRDT_MDUM_CLSN_CODE_NAME AS LEV2_NM /* 13 표준상품중분류코드명 */
FROM SID.IDO_A_IRA_STD_PD_CLSN_CD /* 표준상품분류코드 */
) B ON (A.GDS_NO = B.GDS_NO) WHEN MATCHED THEN UPDATE SET A.GDS_DIT_CD = B.GDS_DIT_CD /* 2 KOFIU상품분류코드 */ , A.GDS_NM = B.GDS_NM /* 3 표준상품분류코드명 */ , A.GDS_DIT_NM = B.GDS_DIT_NM /* 4 KOFIU상품분류코드명 */ , A.GDS_MRK = B.GDS_MRK /* 5 상품RA점수 */ , A.HNDL_DY_TM = B.HNDL_DY_TM /* 6 처리일시 */ , A.HNDL_P_ENO = B.HNDL_P_ENO /* 7 처리자사번 */ , A.AML_CRT_DT = B.AML_CRT_DT /* 8 AML생성일자 */ , A.AML_HNDL_P_ENO = B.AML_HNDL_P_ENO /* 9 AML처리자사번 */ , A.LEV1_CD = B.LEV1_CD /* 10 표준상품대분류코드 */ , A.LEV2_CD = B.LEV2_CD /* 11 표준상품중분류코드 */ , A.LEV1_NM = B.LEV1_NM /* 12 표준상품대분류코드명 */ , A.LEV2_NM = B.LEV2_NM /* 13 표준상품중분류코드명 */ WHEN NOT MATCHED THEN INSERT ( GDS_NO /* 1 표준상품분류코드 */ , GDS_DIT_CD /* 2 KOFIU상품분류코드 */ , GDS_NM /* 3 표준상품분류코드명 */ , GDS_DIT_NM /* 4 KOFIU상품분류코드명 */ , GDS_MRK /* 5 상품RA점수 */ , HNDL_DY_TM /* 6 처리일시 */ , HNDL_P_ENO /* 7 처리자사번 */ , AML_CRT_DT /* 8 AML생성일자 */ , AML_HNDL_P_ENO /* 9 AML처리자사번 */ , LEV1_CD /* 10 표준상품대분류코드 */ , LEV2_CD /* 11 표준상품중분류코드 */ , LEV1_NM /* 12 표준상품대분류코드명 */ , LEV2_NM /* 13 표준상품중분류코드명 */ , USE_YN /* 14 사용여부 */ ) VALUES ( B.GDS_NO /* 1 표준상품분류코드 */ , B.GDS_DIT_CD /* 2 KOFIU상품분류코드 */ , B.GDS_NM /* 3 표준상품분류코드명 */ , B.GDS_DIT_NM /* 4 KOFIU상품분류코드명 */ , B.GDS_MRK /* 5 상품RA점수 */ , B.HNDL_DY_TM /* 6 처리일시 */ , B.HNDL_P_ENO /* 7 처리자사번 */ , B.AML_CRT_DT /* 8 AML생성일자 */ , B.AML_HNDL_P_ENO /* 9 AML처리자사번 */ , B.LEV1_CD /* 10 표준상품대분류코드 */ , B.LEV2_CD /* 11 표준상품중분류코드 */ , B.LEV1_NM /* 12 표준상품대분류코드명 */ , B.LEV2_NM /* 13 표준상품중분류코드명 */ , 'N' /* 14 사용여부 */ )

MERGE INTO SSQ.C_USER A USING ( SELECT REPLACE(REPLACE(A.USER_ID,'TM',99), 'T', 9) AS USER_ID /* 1 사용자ID */ , A.DTBR_ENTY_ID AS DEP_ID /* 2 지점ID */ , B.PDSS_FNCL_ROLE_CODE AS POSITION_CODE /* 3 직책코드 */ , A.USER_NAME AS USER_NM /* 4 직원명 */ , A.USER_ID AS LOGIN_ID /* 5 직원사번 */ , 'MzVlZTVjMGQ2NWQyZjg0YjhmYTMwOWRiY2IyYzg1ZDhhZDZjOTRkZA==' AS USER_PWD /* 6 직원비밀번호(samsung1!) */ , NULL AS USER_IP /* 7 직원IP */ , NULL AS SOC_NO /* 8 전화번호 */ , A.EMAL_ADRS_CRYP AS EMAIL /* 9 이메일 */ , NULL AS CELL_PHONE /* 10 핸드폰번호 */ , DECODE(A.LOA_SECT_CODE,'1','N','Y') AS ACTIVE_YN /* 11 활성여부 */ , A.OFF_DAY_YN AS OFF_DUTY_YN /* 12 부재여부 */ , NULL AS LAST_USE_DATE /* 13 최종접속일 */ , NULL AS LAST_USE_IP /* 14 최종접속IP */ , 0 AS PWD_FAIL_COUNT /* 15 비밀번호 실패건수 */ , NULL AS CRE_ID /* 16 생성자ID */ , TO_CHAR(SYSDATE, 'YYYYMMDDHH24MISS') AS CRE_DT /* 17 생성일 */ , NULL AS UPD_ID /* 18 수정자ID */ , NULL AS UPD_DT /* 19 수정일 */ , CASE WHEN A.USER_DEL_YN = 'Y' THEN 'Y' ELSE 'N' END AS DEL_YN /* 20 삭제여부 */ , NULL AS DEL_ID /* 21 삭제ID */ , NULL AS DEL_DT /* 22 삭제일 */ , TO_CHAR(SYSDATE, 'YYYYMMDD') AS VALID_START_DT /* 23 유효시작일 */ , '99991231' AS VALID_END_DT /* 24 유효종료일 */ , A.MOBL_PHON_IDNF_NO_CRYP AS MOBL_PHON_IDNF_NO_CRYP /* 25 휴대전화식별번호암호문 */ , A.MOBL_PHON_ECNO_CRYP AS MOBL_PHON_ECNO_CRYP /* 26 휴대전화국번호암호문 */ , A.MOBL_PHON_JNPR_NO_CRYP AS MOBL_PHON_JNPR_NO_CRYP /* 27 휴대전화번호암호문 */ , A.EXNO1_PHON_ECNO_CRYP AS EXNO1_PHON_ECNO_CRYP /* 28 내선번호1전화국번호암호문 */ , A.EXNO1_CRYP AS EXNO1_CRYP /* 29 내선번호1암호문 */ , A.EXNO2_PHON_ECNO_CRYP AS EXNO2_PHON_ECNO_CRYP /* 30 내선번호2전화국번호암호문 */ , A.EXNO2_CRYP AS EXNO2_CRYP /* 31 내선번호2암호문 */ , A.PHON_AR_NO_CRYP AS PHON_AR_NO_CRYP /* 32 지역전화번호암호문 */ , A.PHON_ECNO_CRYP AS PHON_ECNO_CRYP /* 33 전화국번호암호문 */ , A.PHON_JNPR_NO_CRYP AS PHON_JNPR_NO_CRYP /* 34 전화번호암호문 */ , NVL((SELECT 'Y' FROM SSQ.C_USER_GROUP_ROLE WHERE USER_ID = TO_NUMBER(REPLACE(REPLACE(A.USER_ID,'TM','99'), 'T', '9')) GROUP BY USER_ID), 'N') AS AML_ROLE_YN /* 35 AML권한적용여부 */ FROM SID.IDO_R_UWA_USER_V A /* IDO_A_업무공통_사용자기본 */ LEFT OUTER JOIN SID.IDO_A_UUE_EMPLOYEE B /* IDO_A_Entity_Employee */ ON A.USER_ID = B.EMPY_NO AND B.DTBR_CODE NOT IN ('10000', '99999') AND B.DTBR_CODE NOT LIKE 'H%'
WHERE 1 = 1 AND LENGTH(TRIM(A.USER_ID)) = 6 AND (SUBSTR(A.USER_ID, 1, 1) BETWEEN '0' AND '9' OR SUBSTR(A.USER_ID, 1, 2) = 'TM' OR (A.USER_ID LIKE 'T%T' AND A.USER_ID IN ('T0796T','T0180T')) ) AND A.DTBR_ENTY_ID > 0 AND A.USER_ID NOT IN ('555555', '888888', '987001', '999999')
) B ON (A.LOGIN_ID = B.LOGIN_ID) WHEN MATCHED THEN UPDATE SET A.DEP_ID = B.DEP_ID /* 2 지점ID-부지점엔티티ID */ , A.POSITION_CODE = B.POSITION_CODE /* 3 직책코드-직급코드 */ , A.USER_NM = B.USER_NM /* 4 직원명-사용자명 */ , A.USER_IP = B.USER_IP /* 7 직원IP-최종사용IP */ , A.EMAIL = B.EMAIL /* 9 이메일-E-mail주소암호문 */ , A.ACTIVE_YN = B.ACTIVE_YN /* 11활성여부-휴직구분코드(01842:0-정상,1-휴직,2-복직) */ , A.OFF_DUTY_YN = B.OFF_DUTY_YN /* 12 부재여부-휴무일여부 */ , A.DEL_YN = B.DEL_YN /* 20 삭제여부 */ , A.MOBL_PHON_IDNF_NO_CRYP = B.MOBL_PHON_IDNF_NO_CRYP /* 25 휴대전화식별번호암호문 */ , A.MOBL_PHON_ECNO_CRYP = B.MOBL_PHON_ECNO_CRYP /* 26 휴대전화국번호암호문 */ , A.MOBL_PHON_JNPR_NO_CRYP = B.MOBL_PHON_JNPR_NO_CRYP /* 27 휴대전화가입자번호암호문 */ , A.EXNO1_PHON_ECNO_CRYP = B.EXNO1_PHON_ECNO_CRYP /* 28 내선번호1전화국번호암호문 */ , A.EXNO1_CRYP = B.EXNO1_CRYP /* 29 내선번호1암호문 */ , A.EXNO2_PHON_ECNO_CRYP = B.EXNO2_PHON_ECNO_CRYP /* 30 내선번호2전화국번호암호문 */ , A.EXNO2_CRYP = B.EXNO2_CRYP /* 31 내선번호2암호문 */ , A.PHON_AR_NO_CRYP = B.PHON_AR_NO_CRYP /* 32 전화지역번호암호문 */ , A.PHON_ECNO_CRYP = B.PHON_ECNO_CRYP /* 33 전화국번호암호문 */ , A.PHON_NO_CRYP = B.PHON_JNPR_NO_CRYP /* 34 전화번호암호문 */ , A.AML_ROLE_YN = B.AML_ROLE_YN WHEN NOT MATCHED THEN INSERT ( USER_ID , DEP_ID , POSITION_CODE , USER_NM , LOGIN_ID , USER_PWD , USER_IP , SOC_NO , EMAIL , CELL_PHONE , ACTIVE_YN , OFF_DUTY_YN , LAST_USE_DATE , LAST_USE_IP , PWD_FAIL_COUNT , CRE_ID , CRE_DT , UPD_ID , UPD_DT , DEL_YN , DEL_ID , DEL_DT , VALID_START_DT , VALID_END_DT , MOBL_PHON_IDNF_NO_CRYP , MOBL_PHON_ECNO_CRYP , MOBL_PHON_JNPR_NO_CRYP , EXNO1_PHON_ECNO_CRYP , EXNO1_CRYP , EXNO2_PHON_ECNO_CRYP , EXNO2_CRYP , PHON_AR_NO_CRYP , PHON_ECNO_CRYP , PHON_NO_CRYP , AML_ROLE_YN ) VALUES ( B.USER_ID , B.DEP_ID , B.POSITION_CODE , B.USER_NM , B.LOGIN_ID , B.USER_PWD , B.USER_IP , B.SOC_NO , B.EMAIL , B.CELL_PHONE , B.ACTIVE_YN , B.OFF_DUTY_YN , B.LAST_USE_DATE , B.LAST_USE_IP , B.PWD_FAIL_COUNT , B.CRE_ID , B.CRE_DT , B.UPD_ID , B.UPD_DT , B.DEL_YN , B.DEL_ID , B.DEL_DT , B.VALID_START_DT , B.VALID_END_DT , B.MOBL_PHON_IDNF_NO_CRYP , B.MOBL_PHON_ECNO_CRYP , B.MOBL_PHON_JNPR_NO_CRYP , B.EXNO1_PHON_ECNO_CRYP , B.EXNO1_CRYP , B.EXNO2_PHON_ECNO_CRYP , B.EXNO2_CRYP , B.PHON_AR_NO_CRYP , B.PHON_ECNO_CRYP , B.PHON_JNPR_NO_CRYP , B.AML_ROLE_YN )

MERGE INTO C_USER_DETAIL A USING ( SELECT USER_ID , '4401' AS DETAIL_CD , '19000101' AS DETAIL FROM SSQ.C_USER
UNION ALL SELECT USER_ID , 'ACCESSIBLE_IP' AS DETAIL_CD , '' AS DETAIL FROM SSQ.C_USER
) B ON (A.USER_ID = B.USER_ID AND A.DETAIL_CD = B.DETAIL_CD ) WHEN NOT MATCHED THEN INSERT ( USER_ID , DETAIL_CD , DETAIL ) VALUES ( B.USER_ID , B.DETAIL_CD , B.DETAIL )

INSERT INTO C_USER_GROUP_ROLE /* 준법감시인 추출 */ /* SELECT TO_NUMBER(B.USER_ID) , 5 , 104 , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') FROM SID.IDO_A_UUE_EMPLOYEE A , SSQ.C_USER B WHERE A.DTBR_CODE = '27200' AND TRIM(A.RSGT_DATE) IS NULL AND A.PDSS_FNCL_ROLE_CODE = 'A6E' AND A.EMPY_NO = B.LOGIN_ID
SELECT TO_NUMBER(C.DPMG_EMPY_NO ) , 5 , 104 , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') FROM SID.IDO_A_UUE_EMPLOYEE A , SSQ.C_USER B , SID.IDO_A_UUE_SAMSUNG_DPRT C WHERE A.DTBR_CODE = '27260' AND TRIM(A.RSGT_DATE) IS NULL AND A.EMPY_NO = B.LOGIN_ID AND A.DTBR_CODE = C.DTBR_CODE
UNION ALL */ /* 지점책임자(지점장) */
/* SELECT DISTINCT TO_NUMBER(C.USER_ID) , 5 , CASE WHEN B.DTBR_CODE = '20170' THEN 5 ELSE 6 END -- 준법팀장은 5 , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') FROM SID.IDO_A_UUE_EMPLOYEE A , SID.IDO_A_UUE_SAMSUNG_DPRT B , SSQ.C_USER C WHERE A.EMPY_NO = B.DPMG_EMPY_NO -- 부서장사원번호 AND A.DTBR_CODE = B.DTBR_CODE -- 부서장으로 세팅된 부서와 사용자의 소속부서가 같은 경우만 AND B.CLSG_YN <> 'Y' -- 폐쇄되지 않은 지점만 AND B.DTBR_CODE NOT IN ('23070','21070','27200') AND A.EMPY_NO = C.LOGIN_ID */ -- 20190416 구자성 : UUE_EMPLOYEE 테이블에서 UWA_USER 테이블로 변경(디지털지점장 누락 케이스 발생) SELECT DISTINCT TO_NUMBER(C.USER_ID) , 5 , CASE WHEN B.DTBR_CODE = '23800' THEN 104 ELSE 6 END /* 컴플라이언스운영팀장은 5에서 104로 변경 */ , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') FROM SID.IDO_A_UWA_USER A , SID.IDO_A_UUE_SAMSUNG_DPRT B , SSQ.C_USER C WHERE A.USER_ID = B.DPMG_EMPY_NO -- 부서장사원번호 AND A.DTBR_ENTY_ID = B.ENTY_ID -- 부서장으로 세팅된 부서와 사용자의 소속부서가 같은 경우만 AND B.CLSG_YN <> 'Y' -- 폐쇄되지 않은 지점만 AND B.DTBR_CODE NOT IN ('23070','21070','27200','20150', '27260') -- 20150 법무팀, 27260 컴플담당 제외(준법감시인 겸직으로 일시제외 : 책임자 권한이 우선 부여돼서 불편) AND A.USER_ID = C.LOGIN_ID
UNION ALL
/* 각지/부점별준법(RBA)담당자 */ SELECT DISTINCT /* 2019.12.13 구자성. 중복제거 추가 */ TO_NUMBER(B.USER_ID) , 5 , 105 , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') FROM SID.IDO_A_UWA_DPRT_CMOF A , SSQ.C_USER B , SID.IDO_A_UUE_SAMSUNG_DPRT C WHERE A.SCRY_CHPR_ID = B.LOGIN_ID AND A.RGSN_DPRT_ENTY_ID = C.ENTY_ID AND C.CLSG_YN = 'N'
UNION ALL
/* 각지/부점별 CSPB팀장 2019.08.05 구자성 추가 */
SELECT TO_NUMBER(B.USER_ID) , 5 , 105 , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') FROM SID.IDO_A_UWA_USER_AUTH A , SSQ.C_USER B , SID.IDO_A_UUE_SAMSUNG_DPRT C WHERE A.USER_ID = B.LOGIN_ID AND B.DEP_ID = C.ENTY_ID AND A.USER_ATHR_CODE = 'JMB50' AND C.CLSG_YN = 'N' AND B.DEL_YN = 'N' AND C.DTBR_CODE LIKE '1%' AND NOT EXISTS (SELECT 1 FROM SID.IDO_A_UWA_DPRT_CMOF T WHERE T.SCRY_CHPR_ID = B.LOGIN_ID)
UNION ALL
/* 삼성증권 준법감시팀원 */ SELECT TO_NUMBER(B.USER_ID) , 5 , 4 , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') FROM SSQ.NIC92B A , SSQ.C_USER B where A.cd LIKE 'S091' AND A.CNTNT = B.LOGIN_ID AND A.USE_F = 'Y' AND B.LOGIN_ID NOT IN (SELECT CNTNT FROM SSQ.NIC92B WHERE CD = 'S094')
UNION ALL
/* 삼성증권 IT담당자 */ SELECT TO_NUMBER(B.USER_ID) , 5 , 7 , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') FROM SSQ.NIC92B A , SSQ.C_USER B where A.cd LIKE 'S092' AND A.CNTNT = B.LOGIN_ID
UNION ALL
/* 삼성증권 컴플라이언스운영팀 책임자 */ SELECT TO_NUMBER(B.USER_ID) , 5 , 5 , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') , 999999 , TO_CHAR(SYSDATE,'YYYYMMDDHH24MISS') FROM SSQ.NIC92B A , SSQ.C_USER B where A.cd LIKE 'S094' AND A.CNTNT = B.LOGIN_ID

MERGE INTO SSQ.NIC81B_1 A USING ( SELECT TRDG_CODE AS TRDG_CODE /* 01 거래코드 */ , TRIM(TRDG_NAME) AS TRDG_NAME /* 02 거래명 */ , TRIM(DTLS_TRDG_NAME) AS DTLS_TRDG_NAME /* 03 상세거래명 */ , ' ' AS DL_TYP_CD /* 04 거래종류코드 */ , ' ' AS FUNS_SCRS_CODE /* 05 자금증권코드 */ , ' ' AS TRTY_DTLS_CODE /* 06 거래유형상세코드 */ /* 07 사용여부 */ , PRCE_DATE_TIME AS HNDL_DY_TM /* 08 처리일시 */ , 0 AS HNDL_P_ENO /* 09 처리자사번 */ , SYSDATE AS AML_CRT_DT /* 10 AML생성일자 */ /* 11 CTR대상여부 */
FROM SID.IDO_A_UWB_TRD_CD WHERE SUBSTR(TRDG_CODE, 1, 1) IN ('1', '2', '3', '4', '5', '6', '7', '8', '9', '0') ) B ON ( A.TRDG_CODE = B.TRDG_CODE ) WHEN MATCHED THEN UPDATE SET A.TRDG_NAME = B.TRDG_NAME /* 02 거래명 */ , A.DTLS_TRDG_NAME = B.DTLS_TRDG_NAME /* 03 상세거래명 */ , A.HNDL_DY_TM = B.HNDL_DY_TM /* 08 처리일시 */ , A.HNDL_P_ENO = B.HNDL_P_ENO /* 09 처리자사번 */ , A.AML_CRT_DT = B.AML_CRT_DT /* 10 AML생성일자 */ WHEN NOT MATCHED THEN INSERT ( TRDG_CODE /* 01 거래코드 */ , TRDG_NAME /* 02 거래명 */ , DTLS_TRDG_NAME /* 03 상세거래명 */ , DL_TYP_CD /* 04 거래종류코드 */ , FUNS_SCRS_CODE /* 05 자금증권코드 */ , TRTY_DTLS_CODE /* 06 거래유형상세코드 */ , USE_YN /* 07 사용여부 */ , HNDL_DY_TM /* 08 처리일시 */ , HNDL_P_ENO /* 09 처리자사번 */ , AML_CRT_DT /* 10 AML생성일자 */ , CTR_OBJ_YN /* 11 CTR대상여부 */
) VALUES ( B.TRDG_CODE /* 01 거래코드 */ , B.TRDG_NAME /* 02 거래명 */ , B.DTLS_TRDG_NAME /* 03 상세거래명 */ , B.DL_TYP_CD /* 04 거래종류코드 */ , B.FUNS_SCRS_CODE /* 05 자금증권코드 */ , B.TRTY_DTLS_CODE /* 06 거래유형상세코드 */ , 'N' /* 07 사용여부 */ , B.HNDL_DY_TM /* 08 처리일시 */ , B.HNDL_P_ENO /* 09 처리자사번 */ , B.AML_CRT_DT /* 10 AML생성일자 */ , ' ' /* 11 CTR대상여부 */ )
